static inline int min_int(int a, int b) { return (a < b) ? a : b; }

void extract_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = expf(d_I[ei] / 255.0f);
    }
}

void prepare_kernel(long d_Ne, fp* d_I, fp* d_sums, fp* d_sums2) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

void reduce_kernel(long d_Ne, int d_no, int d_mul, fp* d_sums, fp* d_sums2, int gridDim) {
    int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - d_no);
    int df = 0;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < gridDim; bx++) {
        fp d_psum[NUMBER_THREADS];
        fp d_psum2[NUMBER_THREADS];

        int tx;

        for (tx = 0; tx < NUMBER_THREADS; tx++) {
            int ei = bx * NUMBER_THREADS + tx;
            if (ei < d_no) {
                d_psum[tx] = d_sums[ei * d_mul];
                d_psum2[tx] = d_sums2[ei * d_mul];
            } else {
                d_psum[tx] = 0.0f;
                d_psum2[tx] = 0.0f;
            }
        }

        if (nf == NUMBER_THREADS) {
            for (int i = 2; i <= NUMBER_THREADS; i <<= 1) {
                for (tx = 0; tx < NUMBER_THREADS; tx++) {
                    if (((tx + 1) % i) == 0) {
                        d_psum[tx] += d_psum[tx - i / 2];
                        d_psum2[tx] += d_psum2[tx - i / 2];
                    }
                }
            }
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
        } else {
            if (bx != (gridDim - 1)) {
                for (int i = 2; i <= NUMBER_THREADS; i <<= 1) {
                    for (tx = 0; tx < NUMBER_THREADS; tx++) {
                        if (((tx + 1) % i) == 0) {
                            d_psum[tx] += d_psum[tx - i / 2];
                            d_psum2[tx] += d_psum2[tx - i / 2];
                        }
                    }
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[NUMBER_THREADS - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[NUMBER_THREADS - 1];
            } else {
                for (int i = 2; i <= NUMBER_THREADS; i <<= 1) {
                    if (nf >= i) {
                        df = i;
                    }
                }
                for (int i = 2; i <= df; i <<= 1) {
                    for (tx = 0; tx < df; tx++) {
                        if (((tx + 1) % i) == 0 && tx < df) {
                            d_psum[tx] += d_psum[tx - i / 2];
                            d_psum2[tx] += d_psum2[tx - i / 2];
                        }
                    }
                }
                for (tx = df - 1; tx < df; tx++) {
                    for (int i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                        d_psum[tx] += d_sums[i];
                        d_psum2[tx] += d_sums2[i];
                    }
                }
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[df - 1];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[df - 1];
            }
        }
    }
}

void srad_kernel(fp d_lambda,
                 int d_Nr,
                 int d_Nc,
                 long d_Ne,
                 int* d_iN,
                 int* d_iS,
                 int* d_jE,
                 int* d_jW,
                 fp* d_dN,
                 fp* d_dS,
                 fp* d_dE,
                 fp* d_dW,
                 fp d_q0sqr,
                 fp* d_c,
                 fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr) - 1;
        int col = (int)((ei + 1) / d_Nr) + 1 - 1;
        if (((ei + 1) % d_Nr) == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }
        if (ei < d_Ne) {
            fp d_Jc = d_I[ei];
            fp d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
            fp d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
            fp d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
            fp d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

            fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
            fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            fp d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
            fp d_den = 1.0f + (0.25f * d_L);
            fp d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
            fp d_c_loc = 1.0f / (1.0f + d_den);

            if (d_c_loc < 0.0f) {
                d_c_loc = 0.0f;
            } else if (d_c_loc > 1.0f) {
                d_c_loc = 1.0f;
            }

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }
    }
}

void srad2_kernel(fp d_lambda,
                  int d_Nr,
                  int d_Nc,
                  long d_Ne,
                  int* d_iN,
                  int* d_iS,
                  int* d_jE,
                  int* d_jW,
                  fp* d_dN,
                  fp* d_dS,
                  fp* d_dE,
                  fp* d_dW,
                  fp* d_c,
                  fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        int row = (int)((ei + 1) % d_Nr) - 1;
        int col = (int)((ei + 1) / d_Nr) + 1 - 1;
        if (((ei + 1) % d_Nr) == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }
        if (ei < d_Ne) {
            fp d_cN = d_c[ei];
            fp d_cS = d_c[d_iS[row] + d_Nr * col];
            fp d_cW = d_c[ei];
            fp d_cE = d_c[row + d_Nr * d_jE[col]];

            fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

            d_I[ei] = d_I[ei] + 0.25f * d_lambda * d_D;
        }
    }
}

void compress_kernel(long d_Ne, fp* d_I) {
    #pragma omp parallel for schedule(static)
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = logf(d_I[ei]) * 255.0f;
    }
}

void kernel_gpu_opencl_wrapper(fp* image,
                               int Nr,
                               int Nc,
                               long Ne,
                               int niter,
                               fp lambda,
                               long NeROI,
                               int* iN,
                               int* iS,
                               int* jE,
                               int* jW,
                               int iter,
                               int mem_size_i,
                               int mem_size_j) {
    fp* d_I = (fp*)malloc(sizeof(fp) * Ne);
    int* d_iN = (int*)malloc(sizeof(int) * Nr);
    int* d_iS = (int*)malloc(sizeof(int) * Nr);
    int* d_jE = (int*)malloc(sizeof(int) * Nc);
    int* d_jW = (int*)malloc(sizeof(int) * Nc);

    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);

    fp* d_c = (fp*)malloc(sizeof(fp) * Ne);

    fp* d_sums = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);

    memcpy(d_I, image, sizeof(fp) * Ne);
    memcpy(d_iN, iN, sizeof(int) * Nr);
    memcpy(d_iS, iS, sizeof(int) * Nr);
    memcpy(d_jE, jE, sizeof(int) * Nc);
    memcpy(d_jW, jW, sizeof(int) * Nc);

    extract_kernel(Ne, d_I);

    prepare_kernel(Ne, d_I, d_sums, d_sums2);

    int blocks_x = (int)(Ne / NUMBER_THREADS);
    if (Ne % NUMBER_THREADS != 0) {
        blocks_x++;
    }
    int blocks_work_size = blocks_x;
    int mul = 1;
    long no = Ne;

    while (blocks_work_size != 0) {
        reduce_kernel(Ne, blocks_work_size, mul, d_sums, d_sums2, blocks_work_size);
        no = blocks_work_size;
        if (blocks_work_size == 1) {
            blocks_work_size = 0;
        } else {
            mul = mul * NUMBER_THREADS;
            blocks_x = blocks_work_size / NUMBER_THREADS;
            if (blocks_work_size % NUMBER_THREADS != 0) {
                blocks_x++;
            }
            blocks_work_size = blocks_x;
        }
    }

    fp total = d_sums[0];
    fp total2 = d_sums2[0];

    fp meanROI = total / (fp)(NeROI);
    fp meanROI2 = meanROI * meanROI;
    fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
    fp q0sqr = varROI / meanROI2;

    for (iter = 0; iter < niter; iter++) {
        prepare_kernel(Ne, d_I, d_sums, d_sums2);

        blocks_work_size = blocks_x;
        no = Ne;
        mul = 1;
        while (blocks_work_size != 0) {
            reduce_kernel(Ne, blocks_work_size, mul, d_sums, d_sums2, blocks_work_size);
            no = blocks_work_size;
            if (blocks_work_size == 1) {
                blocks_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks_work_size / NUMBER_THREADS;
                if (blocks_work_size % NUMBER_THREADS != 0) {
                    blocks_x++;
                }
                blocks_work_size = blocks_x;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        srad_kernel(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, q0sqr, d_c, d_I);

        srad2_kernel(lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dE, d_dW, d_c, d_I);
    }

    compress_kernel(Ne, d_I);

    memcpy(image, d_I, sizeof(fp) * Ne);

    free(d_I);
    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
    free(d_sums);
    free(d_sums2);
}

int platform_id_inuse = 0;
int device_id_inuse = 0;

int main(int argc, char* argv[]) {
    printf("WG size of kernel = %d \n", NUMBER_THREADS);

    fp* image_ori;
    int image_ori_rows;
    int image_ori_cols;
    long image_ori_elem;

    fp* image;
    int Nr = 0, Nc = 0;
    long Ne;

    int niter = 0;
    fp lambda = 0.0f;

    int r1, r2, c1, c2;
    long NeROI;

    int* iN;
    int* iS;
    int* jE;
    int* jW;

    int iter;
    long i, j;

    int mem_size_i;
    int mem_size_j;

    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                niter = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                lambda = (fp)atof(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (argc >= cur_arg + 2) {
                Nr = atoi(argv[cur_arg + 1]);
                Nc = atoi(argv[cur_arg + 2]);
                cur_arg += 2;
            }
        } else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        } else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    image_ori_rows = 502;
    image_ori_cols = 458;
    image_ori_elem = image_ori_rows * image_ori_cols;

    image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

    read_graphics("../../data/srad/image.pgm", image_ori, image_ori_rows, image_ori_cols, 1);

    Ne = Nr * Nc;

    image = (fp*)malloc(sizeof(fp) * Ne);

    resize(image_ori, image_ori_rows, image_ori_cols, image, Nr, Nc, 1);

    r1 = 0;
    r2 = Nr - 1;
    c1 = 0;
    c2 = Nc - 1;

    NeROI = (r2 - r1 + 1) * (c2 - c1 + 1);

    mem_size_i = sizeof(int) * Nr;
    iN = (int*)malloc(mem_size_i);
    iS = (int*)malloc(mem_size_i);
    mem_size_j = sizeof(int) * Nc;
    jW = (int*)malloc(mem_size_j);
    jE = (int*)malloc(mem_size_j);

    for (i = 0; i < Nr; i++) {
        iN[i] = (int)(i - 1);
        iS[i] = (int)(i + 1);
    }
    for (j = 0; j < Nc; j++) {
        jW[j] = (int)(j - 1);
        jE[j] = (int)(j + 1);
    }

    iN[0] = 0;
    iS[Nr - 1] = Nr - 1;
    jW[0] = 0;
    jE[Nc - 1] = Nc - 1;

    kernel_gpu_opencl_wrapper(image, Nr, Nc, Ne, niter, lambda, NeROI, iN, iS, jE, jW, iter, mem_size_i, mem_size_j);

    write_graphics("./output/image_out.pgm", image, Nr, Nc, 1, 255);

    free(image_ori);
    free(image);
    free(iN);
    free(iS);
    free(jW);
    free(jE);

    return 0;
}
